function hist(
  base: Omit<VitalSnapshot, "date">,
  jitters: Array<Partial<Omit<VitalSnapshot, "date">>>
): VitalSnapshot[] {
  const dates = [
    "2026-06-20", "2026-06-21", "2026-06-22", "2026-06-23",
    "2026-06-24", "2026-06-25", "2026-06-26",
  ];
  return dates.map((date, i) => ({ date, ...base, ...(jitters[i] ?? {}) }));
}

