const STATUS_BADGE: Record<RecordStatus, React.ComponentProps<typeof Badge>["variant"]> = {
  確定済: "success",
  下書き: "warning",
  未記録: "outline",
};

/** その利用者の今日のバイタルに異常があるか（一覧バッジ用）。 */
function hasAbnormalVitals(r: Resident): boolean {
  const v = r.todayVitals ?? r.vitalsHistory.at(-1);
  if (!v) return false;
  return (
    flagValue(v.temp, vitalRanges.temp) !== "normal" ||
    flagValue(v.systolic, vitalRanges.systolic) !== "normal" ||
    flagValue(v.spo2, vitalRanges.spo2) !== "normal" ||
    flagValue(v.pulse, vitalRanges.pulse) !== "normal"
  );
}

export function ResidentBoard({ residents }: { residents: Resident[] }) {
  const [openId, setOpenId] = React.useState<string | null>(null);
  const active = residents.find((r) => r.id === openId) ?? null;

  return (
    <>
      <Card>
        <CardHeader className="pb-3">
          <CardTitle as="h2" className="text-base">本日の利用者・記録状況</CardTitle>
        </CardHeader>
        <CardContent className="px-0 pb-2">
          <ul role="list" className="divide-y divide-border">
            {residents.map((r) => {
              const staff = staffById[r.primaryStaffId];
              const abnormal = hasAbnormalVitals(r);
              return (
                <li key={r.id}>
                  <button
                    type="button"
                    onClick={() => setOpenId(r.id)}
                    aria-haspopup="dialog"
                    className="flex w-full items-center gap-3 px-6 py-3 text-left transition-colors hover:bg-muted/50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
                  >
                    <PersonCell
                      className="flex-1"
                      name={r.name}
                      secondary={`${r.room}号室・${r.careLevel}`}
                      tertiary={`担当: ${staff?.name ?? "—"}`}
                      avatarClassName="bg-primary text-primary-strong-foreground"
                      trailing={
                        <div className="flex items-center gap-1.5">
                          {abnormal ? (
                            <Badge variant="warning" icon={<IconAlertTriangle />}>
                              異常
                            </Badge>
                          ) : null}
